CREATE TABLE IF NOT EXISTS valorapesquisa.email_jobs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), organization_id uuid REFERENCES valorapesquisa.organizations(id), response_id uuid REFERENCES valorapesquisa.responses(id), recipient_email text NOT NULL, subject text NOT NULL, template_key text NOT NULL DEFAULT 'result-ready', payload_json jsonb NOT NULL DEFAULT '{}'::jsonb, status text NOT NULL DEFAULT 'pending', attempts int NOT NULL DEFAULT 0, last_error text, scheduled_at timestamptz NOT NULL DEFAULT now(), processing_at timestamptz, sent_at timestamptz, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), created_by uuid, updated_by uuid, is_deleted boolean NOT NULL DEFAULT false);
CREATE TABLE IF NOT EXISTS valorapesquisa.whatsapp_jobs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), organization_id uuid REFERENCES valorapesquisa.organizations(id), response_id uuid REFERENCES valorapesquisa.responses(id), recipient_phone text NOT NULL, template_key text NOT NULL DEFAULT 'result-ready', payload_json jsonb NOT NULL DEFAULT '{}'::jsonb, status text NOT NULL DEFAULT 'pending', attempts int NOT NULL DEFAULT 0, last_error text, scheduled_at timestamptz NOT NULL DEFAULT now(), sent_at timestamptz, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), created_by uuid, updated_by uuid, is_deleted boolean NOT NULL DEFAULT false);
CREATE TABLE IF NOT EXISTS valorapesquisa.communications (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), organization_id uuid REFERENCES valorapesquisa.organizations(id), survey_id uuid REFERENCES valorapesquisa.surveys(id), response_id uuid REFERENCES valorapesquisa.responses(id), channel text NOT NULL, event_type text NOT NULL, status text NOT NULL DEFAULT 'pending', recipient_masked text, provider_message_id text, attempts int NOT NULL DEFAULT 0, last_error text, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), created_by uuid, updated_by uuid, is_deleted boolean NOT NULL DEFAULT false, sent_at timestamptz);
